#include <stdio.h>
#include <unistd.h>
#include <sys/types.h>

int main() {
 pid_t pid;

 printf("Before fork - Parent PID: %d\n", getpid());

 pid = fork(); // Creates new process

 if (pid < 0) {
 // Error occurred
 perror("fork failed");
 return 1;
 }
 else if (pid == 0) {
 // Child process
 printf("Child: My PID = %d, Parent PID = %d\n", 
 getpid(), getppid());
 // Typically would call exec() here
 }
 else {
 // Parent process
 printf("Parent: Child PID = %d, My PID = %d\n", 
 pid, getpid());
 wait(NULL); // Wait for child to finish
 }

 printf("After fork - PID: %d\n", getpid());
 return 0;
}

#include <stdio.h>
#include <fcntl.h>
#include <unistd.h>

int main() {
 int fd;
 char buffer[100];
 ssize_t bytes_read, bytes_written;

 // Create and open file (O_CREAT: create if not exists, O_WRONLY: write only)
 fd = open("test.txt", O_CREAT | O_WRONLY | O_TRUNC, 0644);

 if (fd == -1) {
 perror("open failed");
 return 1;
 }

 // Write to file
 char *msg = "Hello, System Calls!\n";
 bytes_written = write(fd, msg, 22);
 printf("Written %zd bytes\n", bytes_written);

 // Close file
 close(fd);

 // Open again for reading
 fd = open("test.txt", O_RDONLY);
 if (fd == -1) {
 perror("open for read failed");
 return 1;
 }

 // Read from file
 bytes_read = read(fd, buffer, sizeof(buffer));
 printf("Read %zd bytes: %s", bytes_read, buffer);

 // Use lseek to reposition file pointer
 lseek(fd, 0, SEEK_SET); // Go to beginning
 bytes_read = read(fd, buffer, sizeof(buffer));

 close(fd);
 return 0;
}

#include <stdio.h>
#include <unistd.h>
#include <string.h>
#include <sys/wait.h>

int main() {
 int pipefd[2]; // pipefd[0]: read end, pipefd[1]: write end
 pid_t pid;
 char write_msg[] = "Message from parent to child!";
 char read_buffer[100];

 // Create pipe
 if (pipe(pipefd) == -1) {
 perror("pipe failed");
 return 1;
 }

 pid = fork();

 if (pid < 0) {
 perror("fork failed");
 return 1;
 }

 if (pid == 0) {
 // Child process
 close(pipefd[1]); // Close write end

 // Read from pipe
 read(pipefd[0], read_buffer, sizeof(read_buffer));
 printf("Child received: %s\n", read_buffer);

 close(pipefd[0]);
 } 
 else {
 // Parent process
 close(pipefd[0]); // Close read end

 // Write to pipe
 write(pipefd[1], write_msg, strlen(write_msg) + 1);
 printf("Parent sent message\n");

 close(pipefd[1]);
 wait(NULL); // Wait for child
 }

 return 0;
}

#include <stdio.h>
#include <unistd.h>
#include <sys/wait.h>
#include <stdlib.h>

int main() {
 pid_t pid;

 pid = fork();

 if (pid < 0) {
 perror("fork failed");
 return 1;
 }

 if (pid == 0) {
 // Child process - replace with new program
 // execlp searches PATH for the command
 execlp("ls", "ls", "-l", (char *)NULL);

 // If execlp returns, an error occurred
 perror("execlp failed");
 exit(1);
 }
 else {
 // Parent process - wait for child to complete
 int status;
 waitpid(pid, &status, 0);

 if (WIFEXITED(status)) {
 printf("Child exited with status: %d\n", 
 WEXITSTATUS(status));
 }
 }

 return 0;
}

#include <stdio.h>
#include <signal.h>
#include <unistd.h>
#include <stdlib.h>

// Signal handler function
void handle_sigint(int sig_num) {
 printf("\nCaught signal %d (SIGINT - Ctrl+C)\n", sig_num);
 printf("Cleaning up and exiting...\n");
 // Perform cleanup operations
 exit(0);
}

int main() {
 // Register signal handler for SIGINT (Ctrl+C)
 signal(SIGINT, handle_sigint);

 printf("Press Ctrl+C to trigger signal handler\n");
 printf("Process PID: %d\n", getpid());

 // Infinite loop - wait for signal
 while(1) {
 printf("Running...\n");
 sleep(2);
 }

 return 0;
}
